export const scaleHtml = `<!--
  当页面整体缩放时，需传入缩放倍率
-->
<div id="content">
  <div class="list scoped" data-scoped="1">
    <div class="list-item incontroll">落焦点-item-1</div>
    <div class="list-item incontroll">落焦点-item-2</div>
  </div>
</div>

<style>
  // 假设屏幕宽度是1440px，则缩放比例为 0.75
  html {
    transform-origin: left top;
    -webkit-transform-origin: left top;
    transform: scale(0.75);
    -webkit-transform: scale(0.75);  
    font-size: 100px !important;
    width: 1920px;
    height: 1080px;
    overflow: hidden;
  }
</style>
`;

export const scaleJs = `import { LayerScoper } from 'layer-scoper';

const layerScoperCase = new LayerScoper();

/* 
  页面启动缩放单位换算:

  如果是 px 为单位的，则直接使用实际 px 数值      
  cssUsedScrrenMultipler = false 即可

  如果是 rem/vw/vh/em/vm/vmin/vmax 为单位的，则需要根据实际屏幕宽度计算倍率
  cssUsedScrrenMultipler = true 且 screenMultiplerValue 为实际倍率值

*/

例如页面启动的是缩放方式: 假设屏幕宽度是1440px，则缩放比例为 0.75
  const screenMultiplerValue = 1;
  if (window.innerWidth === 1280) {
    screenMultiplerValue = 0.666667;
  } else {
    screenMultiplerValue = window.innerWidth / 1920;      1440 / 1920 = 0.75
  }

mounted() {
  layerScoperCase.initController({
    id: 'content',
    className: 'incontroll',
    defaultPoint: { y: 1, x: 1 },
    cssUsedScrrenMultipler: true, // 开启缩放倍率换算
    screenMultiplerValue: screenMultiplerValue, // 传入实际缩放比例
  });
}
...
`;
